INSERT INTO pages VALUES(2,'À propos','<p><strong>GrimbaNews</strong> est un média francophone indépendant édité par Iboga Ventures. Nous aidons nos lectrices et lecteurs à voir chaque angle de chaque histoire : nous classons le biais éditorial, identifions les angles morts, notons la crédibilité des sources.</p><p>Notre rédaction est basée en France et collabore avec des correspondants en Afrique francophone.</p><p>Pour comprendre comment nous travaillons, lisez notre <a href="/methodologie">méthodologie</a>.</p>',1,NULL,'grimba-chrome',NULL,'published','2026-04-23 17:32:22','2026-04-23 20:44:55');
INSERT INTO pages VALUES(3,'Contact','<p>Écrivez-nous à <a href="mailto:contact@grimbanews.com">contact@grimbanews.com</a>.</p><p>Pour contester un classement de source, utilisez l''adresse dédiée <a href="mailto:methodologie@grimbanews.com">methodologie@grimbanews.com</a>. Chaque contestation reçoit une réponse publique sous quinze jours.</p><p>Pour une opportunité commerciale, partenariat ou presse : <a href="mailto:partenariats@grimbanews.com">partenariats@grimbanews.com</a>.</p>',1,NULL,'grimba-chrome',NULL,'published','2026-04-23 17:32:22','2026-04-23 20:44:55');
INSERT INTO pages VALUES(4,'Blog','---',1,NULL,'full-width',NULL,'published','2026-04-23 17:32:22','2026-04-23 17:32:22');
INSERT INTO pages VALUES(5,'Team','<div>[members title="Meet Our Professional Team" member_ids="1,2,3,4,5,6,7,8"][/members]</div>',1,NULL,'full-width',NULL,'published','2026-04-23 17:32:22','2026-04-23 17:32:22');
INSERT INTO pages VALUES(6,'Cookie Policy','<h3>EU Cookie Consent</h3><p>To use this website we are using Cookies and collecting some Data. To be compliant with the EU GDPR we give you to choose if you allow us to use certain Cookies and to collect some Data.</p><h4>Essential Data</h4><p>The Essential Data is needed to run the Site you are visiting technically. You can not deactivate them.</p><p>- Session Cookie: PHP uses a Cookie to identify user sessions. Without this Cookie the Website is not working.</p><p>- XSRF-Token Cookie: Laravel automatically generates a CSRF "token" for each active user session managed by the application. This token is used to verify that the authenticated user is the one actually making the requests to the application.</p>',1,NULL,'default',NULL,'published','2026-04-23 17:32:22','2026-04-23 17:32:22');
INSERT INTO pages VALUES(7,'Conditions d''utilisation','<p>Ces conditions régissent l''utilisation de GrimbaNews. En accédant au site, vous les acceptez.</p><h2>Usage</h2><p>Le contenu éditorial est protégé par le droit d''auteur. Vous pouvez partager les articles via leurs liens canoniques. La reproduction intégrale est soumise à notre accord écrit.</p><h2>Classement des sources</h2><p>Nos classements de biais, scores de crédibilité et drapeaux d''angles morts sont publiés de bonne foi mais restent des évaluations éditoriales et non des jugements absolus. Consultez la <a href="/methodologie">méthodologie</a> pour comprendre notre démarche.</p><h2>Responsabilité</h2><p>GrimbaNews s''efforce de présenter des informations exactes mais ne peut garantir l''absence totale d''erreur. Les contestations et corrections sont bienvenues.</p><h2>Modifications</h2><p>Ces conditions peuvent évoluer. Les changements matériels seront annoncés en page d''accueil.</p>',1,NULL,'grimba-chrome',NULL,'published','2026-04-23 17:32:22','2026-04-23 20:44:55');
INSERT INTO pages VALUES(8,'Politique de confidentialité','<p>GrimbaNews collecte un minimum d''informations personnelles. Cette page explique ce que nous stockons, pourquoi, et comment le supprimer.</p><h2>Données collectées</h2><ul><li>Adresse e-mail (uniquement si vous vous inscrivez à notre infolettre)</li><li>Cookie <code>grimba_follow</code> — stocké localement pour mémoriser les sujets que vous suivez (aucune donnée envoyée à nos serveurs sans action de votre part)</li><li>Cookie <code>grimba_theme</code> — votre préférence d''affichage Clair / Sombre / Auto</li><li>Journaux d''accès anonymisés (adresse IP tronquée) conservés 90 jours pour la sécurité</li></ul><h2>Vos droits</h2><p>Conformément au RGPD, vous pouvez accéder, rectifier ou supprimer vos données sur simple demande à <a href="mailto:privacy@grimbanews.com">privacy@grimbanews.com</a>.</p><h2>Publicité</h2><p>Nous n''utilisons aucun traceur publicitaire tiers. GrimbaNews se finance par les abonnements et le mécénat.</p>',1,NULL,'grimba-chrome',NULL,'published','2026-04-23 17:32:22','2026-04-23 20:44:55');
