INSERT INTO pages VALUES(11,'Carrières','<p>GrimbaNews recrute en continu des talents qui croient qu''une information équilibrée, classée et documentée peut changer le débat démocratique francophone.</p><h2>Postes ouverts</h2><ul><li>Journaliste senior (Paris / remote FR)</li><li>Développeur full-stack Laravel / Node (remote)</li><li>Analyste sources médias francophones (CDI)</li></ul><p>Candidatures spontanées bienvenues : <a href="mailto:carrieres@grimbanews.com">carrieres@grimbanews.com</a>.</p>',NULL,NULL,'grimba-chrome',NULL,'published','2026-04-23 20:44:55','2026-04-23 20:44:55');
