INSERT INTO posts VALUES(67,'Réforme des retraites : les syndicats appellent à une grève générale le 3 mai','Unité intersyndicale inédite. Les huit principales centrales dénoncent un texte qui allongerait la durée de cotisation à 43 ans d''ici 2029 et réclament son retrait pur et simple. Mobilisation annoncée dans 180 villes.','<p>Unité intersyndicale inédite. Les huit principales centrales dénoncent un texte qui allongerait la durée de cotisation à 43 ans d''ici 2029 et réclament son retrait pur et simple. Mobilisation annoncée dans 180 villes.</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',1,'grimba-seeds/cluster-1001-le-monde.svg',3605,NULL,'2026-04-23 19:44:44','2026-04-23 20:57:44','left',0,88,'independent',1001,'Le Monde',1,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(68,'Retraites : le gouvernement confirme l''allongement à 43 ans, l''Assemblée débat mardi','Le Premier ministre a présenté ce lundi les grandes lignes de la réforme devant les partenaires sociaux. Le texte sera examiné en première lecture dès mardi. Calendrier serré, points d''équilibre encore en négociation.','<p>Le Premier ministre a présenté ce lundi les grandes lignes de la réforme devant les partenaires sociaux. Le texte sera examiné en première lecture dès mardi. Calendrier serré, points d''équilibre encore en négociation.</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',1,'grimba-seeds/cluster-1001-afp.svg',4545,NULL,'2026-04-23 18:10:44','2026-04-23 20:57:44','center',0,92,'state',1001,'AFP',4,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(69,'Retraites : pourquoi l''allongement de la durée de cotisation est devenu incontournable','Vieillissement démographique, déficit croissant du régime général et pression des marchés obligataires : l''éditorial défend une réforme présentée comme condition de la soutenabilité du système français.','<p>Vieillissement démographique, déficit croissant du régime général et pression des marchés obligataires : l''éditorial défend une réforme présentée comme condition de la soutenabilité du système français.</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/cluster-1001-le-figaro.svg',1761,NULL,'2026-04-23 19:30:44','2026-04-23 20:57:44','right',0,85,'corporate',1001,'Le Figaro',6,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(70,'Climat : derrière l''accord de Bruxelles, les ONG dénoncent des exemptions pour l''industrie lourde','L''enquête révèle plus de 180 pages d''annexes techniques ouvrant des dérogations au marché carbone pour l''acier, le ciment et la chimie. Six ONG parlent d''un « texte vidé de sa substance ».','<p>L''enquête révèle plus de 180 pages d''annexes techniques ouvrant des dérogations au marché carbone pour l''acier, le ciment et la chimie. Six ONG parlent d''un « texte vidé de sa substance ».</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/cluster-1002-mediapart.svg',4368,NULL,'2026-04-23 12:59:44','2026-04-23 20:57:44','left',0,82,'independent',1002,'Mediapart',3,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(71,'L''Union européenne adopte son nouveau paquet climat : −55 % d''émissions en 2030','Après 28 heures de négociations à Bruxelles, les vingt-sept États membres ont acté un nouveau mécanisme d''ajustement carbone aux frontières et l''extension de l''ETS au transport maritime et à la construction.','<p>Après 28 heures de négociations à Bruxelles, les vingt-sept États membres ont acté un nouveau mécanisme d''ajustement carbone aux frontières et l''extension de l''ETS au transport maritime et à la construction.</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',1,'grimba-seeds/cluster-1002-france-24.svg',2269,NULL,'2026-04-23 10:24:44','2026-04-23 20:57:44','center',0,85,'state',1002,'France 24',5,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(72,'Accord climat européen : un coût de 400 milliards pour les ménages, alerte la CEA','Le rapport du Conseil d''analyse économique chiffre l''impact du paquet sur le pouvoir d''achat. Les filières automobile et logement seront les plus exposées. L''éditorial réclame une « pause réglementaire ».','<p>Le rapport du Conseil d''analyse économique chiffre l''impact du paquet sur le pouvoir d''achat. Les filières automobile et logement seront les plus exposées. L''éditorial réclame une « pause réglementaire ».</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/cluster-1002-valeurs-actuelles.svg',4638,NULL,'2026-04-23 14:19:44','2026-04-23 20:57:44','right',0,60,'corporate',1002,'Valeurs Actuelles',7,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(73,'Sahel : l''armée française quitte le Niger, Paris cherche un nouveau cadre','Plus de mille soldats ont été repliés vers N''Djamena. La tribune d''une vingtaine de chercheurs africains appelle la France à sortir de la logique militaire et à soutenir les initiatives de la CEDEAO.','<p>Plus de mille soldats ont été repliés vers N''Djamena. La tribune d''une vingtaine de chercheurs africains appelle la France à sortir de la logique militaire et à soutenir les initiatives de la CEDEAO.</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/cluster-1003-liberation.svg',4976,NULL,'2026-04-22 20:05:44','2026-04-23 20:57:44','left',0,80,'corporate',1003,'Libération',2,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(74,'Dépêche : le dernier convoi militaire français a franchi la frontière nigéro-tchadienne','Confirmation officielle du porte-parole de l''état-major. Fin d''une présence de onze ans. Les autorités militaires nigériennes saluent « un retrait ordonné ». Réactions diplomatiques attendues en fin de journée.','<p>Confirmation officielle du porte-parole de l''état-major. Fin d''une présence de onze ans. Les autorités militaires nigériennes saluent « un retrait ordonné ». Réactions diplomatiques attendues en fin de journée.</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/cluster-1003-afp.svg',4464,NULL,'2026-04-22 13:51:44','2026-04-23 20:57:44','center',0,92,'state',1003,'AFP',4,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(75,'Sahel : le retrait français ouvre un boulevard à la Russie et à la Chine, analyse','L''éditorialiste décrypte les implications géopolitiques du désengagement. Groupe Wagner, contrats miniers, diplomatie parallèle : l''analyse plaide pour un repositionnement stratégique.','<p>L''éditorialiste décrypte les implications géopolitiques du désengagement. Groupe Wagner, contrats miniers, diplomatie parallèle : l''analyse plaide pour un repositionnement stratégique.</p><p>Article de démonstration — GrimbaNews. Le contenu complet sera fourni par la rédaction.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/cluster-1003-lopinion.svg',3566,NULL,'2026-04-22 23:32:44','2026-04-23 20:57:44','right',0,72,'corporate',1003,'L''Opinion',8,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(76,'Le Sénégal annonce un plan d''investissement de 2 milliards dans les énergies renouvelables','Le ministre de l''Énergie a présenté une feuille de route sur cinq ans. Objectif : 40 % du mix électrique couvert par le solaire et l''éolien d''ici 2031. Financement international à hauteur de 60 %.','<p>Le ministre de l''Énergie a présenté une feuille de route sur cinq ans. Objectif : 40 % du mix électrique couvert par le solaire et l''éolien d''ici 2031. Financement international à hauteur de 60 %.</p><p>Article de démonstration — GrimbaNews.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/stand-financial-afrik-le-senegal-annonce-un-plan-di.svg',280,NULL,'2026-04-23 18:37:44','2026-04-23 20:57:44','center',0,75,'independent',NULL,'Financial Afrik',19,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(77,'Inflation : la BCE maintient ses taux directeurs à 3,25 % pour le troisième mois consécutif','Christine Lagarde évoque une « trajectoire de désinflation en cours mais fragile ». L''indice des prix à la consommation de la zone euro ressort à 2,4 % en glissement annuel en avril.','<p>Christine Lagarde évoque une « trajectoire de désinflation en cours mais fragile ». L''indice des prix à la consommation de la zone euro ressort à 2,4 % en glissement annuel en avril.</p><p>Article de démonstration — GrimbaNews.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/stand-reuters-inflation-la-bce-maintient-s.svg',677,NULL,'2026-04-22 17:11:44','2026-04-23 20:57:44','center',0,94,'corporate',NULL,'Reuters',9,'en',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(78,'Nouvelle vague d''IA générative : Paris accueille le sommet AI Action 2026','Quarante chefs d''État, OpenAI, Anthropic, Mistral et les acteurs africains de l''IA convergent à Bercy. Un « pacte de Paris sur l''IA » pourrait encadrer la transparence des modèles de fondation.','<p>Quarante chefs d''État, OpenAI, Anthropic, Mistral et les acteurs africains de l''IA convergent à Bercy. Un « pacte de Paris sur l''IA » pourrait encadrer la transparence des modèles de fondation.</p><p>Article de démonstration — GrimbaNews.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/stand-bbc-nouvelle-vague-dia-generative.svg',2474,NULL,'2026-04-23 00:25:44','2026-04-23 20:57:44','center',0,90,'state',NULL,'BBC',11,'en',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(79,'Procès climat : condamnation historique d''une major pétrolière par le tribunal de Paris','Première décision française rendant une multinationale responsable de ses émissions indirectes (scope 3). Astreinte de 75 millions d''euros par an jusqu''à la mise en conformité de la trajectoire climatique.','<p>Première décision française rendant une multinationale responsable de ses émissions indirectes (scope 3). Astreinte de 75 millions d''euros par an jusqu''à la mise en conformité de la trajectoire climatique.</p><p>Article de démonstration — GrimbaNews.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/stand-the-guardian-proces-climat-condamnation-h.svg',318,NULL,'2026-04-23 01:42:44','2026-04-23 20:57:44','left',1,85,'nonprofit',NULL,'The Guardian',12,'en',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(80,'Côte d''Ivoire : la présidentielle 2026 entre en campagne, trois candidats se détachent','Le parti au pouvoir, le RHDP, aligne son poulain face à deux figures historiques de l''opposition. Commission électorale indépendante sous tension. Observateurs de l''UA déployés dès le 15 mai.','<p>Le parti au pouvoir, le RHDP, aligne son poulain face à deux figures historiques de l''opposition. Commission électorale indépendante sous tension. Observateurs de l''UA déployés dès le 15 mai.</p><p>Article de démonstration — GrimbaNews.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/stand-jeune-afrique-cote-divoire-la-presidentie.svg',497,NULL,'2026-04-23 01:51:44','2026-04-23 20:57:44','center',0,82,'independent',NULL,'Jeune Afrique',14,'fr',NULL,NULL,NULL,NULL,NULL);
INSERT INTO posts VALUES(81,'Tennis : Djokovic atteint les demi-finales à Roland-Garros malgré une blessure','Le Serbe s''impose en cinq sets contre l''Italien Musetti. Genou droit strappé, il affrontera Alcaraz vendredi. Première demi-finale pour le numéro 3 mondial depuis deux saisons.','<p>Le Serbe s''impose en cinq sets contre l''Italien Musetti. Genou droit strappé, il affrontera Alcaraz vendredi. Première demi-finale pour le numéro 3 mondial depuis deux saisons.</p><p>Article de démonstration — GrimbaNews.</p>','published',1,'Botble\ACL\Models\User',0,'grimba-seeds/stand-associated-press-tennis-djokovic-atteint-les.svg',1328,NULL,'2026-04-22 16:01:44','2026-04-23 20:57:44','center',0,93,'nonprofit',NULL,'Associated Press',10,'en',NULL,NULL,NULL,NULL,NULL);
