PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "meta_boxes" ("id" integer primary key autoincrement not null, "meta_key" varchar not null, "meta_value" text, "reference_id" integer not null, "reference_type" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "revisions" ("id" integer primary key autoincrement not null, "revisionable_type" varchar not null, "revisionable_id" integer not null, "user_id" integer, "key" varchar not null, "old_value" text, "new_value" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "first_name" varchar, "last_name" varchar, "username" varchar, "avatar_id" integer, "super_user" tinyint(1) not null default '0', "manage_supers" tinyint(1) not null default '0', "permissions" text, "last_login" datetime, "phone" varchar, "sessions_invalidated_at" datetime);
CREATE TABLE IF NOT EXISTS "activations" ("id" integer primary key autoincrement not null, "user_id" integer not null, "code" varchar not null, "completed" tinyint(1) not null default '0', "completed_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "slug" varchar not null, "name" varchar not null, "permissions" text, "description" varchar, "is_default" integer not null default '0', "created_by" integer not null, "updated_by" integer not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "role_users" ("id" integer primary key autoincrement not null, "user_id" integer not null, "role_id" integer not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "menus" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar, "status" varchar not null default 'published', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "dashboard_widgets" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "dashboard_widget_settings" ("id" integer primary key autoincrement not null, "settings" text, "user_id" integer not null, "widget_id" integer not null, "order" integer not null default '0', "status" integer not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "widgets" ("id" integer primary key autoincrement not null, "widget_id" varchar not null, "sidebar_id" varchar not null, "theme" varchar not null, "position" integer not null default '0', "data" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "media_files" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "folder_id" integer not null default '0', "mime_type" varchar not null, "size" integer not null, "url" varchar not null, "options" text, "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "alt" varchar, "visibility" varchar not null default 'public');
CREATE TABLE IF NOT EXISTS "media_settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "media_id" integer, "user_id" integer, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "slugs" ("id" integer primary key autoincrement not null, "key" varchar not null, "reference_id" integer not null, "reference_type" varchar not null, "prefix" varchar default '', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" varchar not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "admin_notifications" ("id" integer primary key autoincrement not null, "title" varchar not null, "action_label" varchar, "action_url" varchar, "description" varchar, "read_at" datetime, "created_at" datetime, "updated_at" datetime, "permission" varchar);
CREATE TABLE IF NOT EXISTS "pages" ("id" integer primary key autoincrement not null, "name" varchar not null, "content" text, "user_id" integer, "image" varchar, "template" varchar, "description" varchar, "status" varchar not null default ('published'), "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "media_folders" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar, "slug" varchar, "parent_id" integer not null default ('0'), "created_at" datetime, "updated_at" datetime, "deleted_at" datetime, "color" varchar);
CREATE TABLE IF NOT EXISTS "user_meta" ("id" integer primary key autoincrement not null, "key" varchar, "value" text, "user_id" integer not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "menu_nodes" ("id" integer primary key autoincrement not null, "menu_id" integer not null, "parent_id" integer not null default ('0'), "reference_id" integer, "reference_type" varchar, "url" varchar, "icon_font" varchar, "position" integer not null default ('0'), "title" varchar, "css_class" varchar, "target" varchar not null default ('_self'), "has_child" integer not null default ('0'), "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "menu_locations" ("id" integer primary key autoincrement not null, "menu_id" integer not null, "location" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "device_tokens" ("id" integer primary key autoincrement not null, "token" varchar not null, "platform" varchar, "app_version" varchar, "device_id" varchar, "user_type" varchar, "user_id" integer, "is_active" tinyint(1) not null default '1', "last_used_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "push_notifications" ("id" integer primary key autoincrement not null, "title" varchar not null, "message" text not null, "type" varchar not null default 'general', "target_type" varchar, "target_value" varchar, "action_url" varchar, "image_url" varchar, "data" text, "status" varchar not null default 'sent', "sent_count" integer not null default '0', "failed_count" integer not null default '0', "delivered_count" integer not null default '0', "read_count" integer not null default '0', "scheduled_at" datetime, "sent_at" datetime, "created_by" integer, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "push_notification_recipients" ("id" integer primary key autoincrement not null, "push_notification_id" integer not null, "user_type" varchar not null, "user_id" integer not null, "device_token" varchar, "platform" varchar, "status" varchar not null default 'sent', "sent_at" datetime, "delivered_at" datetime, "read_at" datetime, "clicked_at" datetime, "fcm_response" text, "error_message" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "user_settings" ("id" integer primary key autoincrement not null, "user_type" varchar not null, "user_id" integer not null, "key" varchar not null, "value" text not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "ads" ("id" integer primary key autoincrement not null, "name" varchar not null, "expired_at" datetime, "location" varchar, "key" varchar not null, "image" varchar, "url" varchar, "clicked" integer not null default '0', "order" integer default '0', "status" varchar not null default 'published', "created_at" datetime, "updated_at" datetime, "open_in_new_tab" tinyint(1) not null default '1', "tablet_image" varchar, "mobile_image" varchar, "ads_type" varchar, "google_adsense_slot_id" varchar);
CREATE TABLE IF NOT EXISTS "ads_translations" ("lang_code" varchar not null, "ads_id" integer not null, "name" varchar, "image" varchar, "url" varchar, "tablet_image" varchar, "mobile_image" varchar, primary key ("lang_code", "ads_id"));
CREATE TABLE IF NOT EXISTS "announcements" ("id" integer primary key autoincrement not null, "name" varchar not null, "content" text not null, "has_action" tinyint(1) not null default '0', "action_label" varchar, "action_url" varchar, "action_open_new_tab" tinyint(1) not null default '0', "dismissible" tinyint(1) not null default '0', "start_date" datetime, "end_date" datetime, "is_active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "announcements_translations" ("lang_code" varchar not null, "announcements_id" integer not null, "content" text, "action_label" varchar, primary key ("lang_code", "announcements_id"));
CREATE TABLE IF NOT EXISTS "audit_histories" ("id" integer primary key autoincrement not null, "user_id" integer not null, "module" varchar not null, "request" text, "action" varchar not null, "user_agent" text, "ip_address" varchar, "actor_id" integer not null, "reference_id" integer not null, "reference_name" varchar not null, "type" varchar not null, "created_at" datetime, "updated_at" datetime, "user_type" varchar default 'Botble\\ACL\\Models\\User', "actor_type" varchar default 'Botble\\ACL\\Models\\User');
CREATE TABLE IF NOT EXISTS "post_tags" ("tag_id" integer not null, "post_id" integer not null);
CREATE TABLE IF NOT EXISTS "post_categories" ("category_id" integer not null, "post_id" integer not null);
