CREATE TABLE IF NOT EXISTS "posts" ("id" integer primary key autoincrement not null, "name" varchar not null, "description" varchar, "content" text, "status" varchar not null default ('published'), "author_id" integer, "author_type" varchar not null, "is_featured" integer not null default ('0'), "image" varchar, "views" integer not null default ('0'), "format_type" varchar, "created_at" datetime, "updated_at" datetime, "bias_rating" varchar default 'unknown', "is_blindspot" tinyint(1) not null default '0', "credibility_score" integer, "ownership_type" varchar, "story_cluster_id" integer, "source_name" varchar, "source_id" integer, "original_language" varchar, "translated_name" text, "translated_description" text, "translated_to" varchar, "translated_at" datetime, "translation_driver" varchar);
