CREATE TABLE IF NOT EXISTS "contact_custom_fields_translations" ("contact_custom_fields_id" integer not null, "lang_code" varchar not null, "name" varchar, "placeholder" varchar, primary key ("lang_code", "contact_custom_fields_id"));
CREATE TABLE IF NOT EXISTS "contact_custom_field_options_translations" ("contact_custom_field_options_id" integer not null, "lang_code" varchar not null, "label" varchar, "value" varchar, primary key ("lang_code", "contact_custom_field_options_id"));
